#!/usr/bin/env python3
"""Generated by superpower-adapter."""

from __future__ import annotations

from pathlib import Path
import sys

from spec_common import repo_root


TEMPLATE = '''## Update: {title}

### Why
- {why}

### Rules / Contracts
-

### Good Example
```text

```

### Bad Example
```text

```

### Validation / Notes
-
'''


def main() -> int:
    target = sys.argv[1] if len(sys.argv) > 1 else '<target-spec>'
    title = sys.argv[2] if len(sys.argv) > 2 else 'New rule or learned behavior'
    why = sys.argv[3] if len(sys.argv) > 3 else 'Describe what this prevents or clarifies.'
    root = repo_root(Path.cwd())
    spec_root = root / '.superpowers' / 'spec'
    print(f'Target spec: {spec_root / target}\n')
    print(TEMPLATE.format(title=title, why=why))
    return 0


if __name__ == '__main__':
    raise SystemExit(main())
